const readMessages = new WeakSet();

function markAsRead(messageObj) {
  readMessages.add(messageObj);
}

let msg1 = { text: 'Hello' };
markAsRead(msg1);

console.log(readMessages.has(msg1)); // true (It's been read)

// User deletes the message from the chat app
msg1 = null;

// Because we used a WeakSet, the memory is instantly freed.
// The WeakSet no longer holds the ghost of msg1.
